<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\StoreFeatureItemRequest; use App\Http\Requests\Admin\UpdateFeatureItemRequest; use App\Models\FeatureItem; use App\Services\FileUploadService; use Illuminate\Http\RedirectResponse; use Illuminate\Support\Facades\Cache; use Illuminate\View\View;
class FeatureItemController extends Controller { public function index(): View { $items=FeatureItem::query()->ordered()->paginate(15); return view('admin.pages.features.index',compact('items')); } public function create(): View { return view('admin.pages.features.form',['item'=>new FeatureItem()]); } public function store(StoreFeatureItemRequest $request, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),null,'uploads/features'); FeatureItem::create($data); $this->clearCache(); return redirect()->route('admin.features.index')->with('success','Feature created successfully.'); } public function edit(FeatureItem $feature): View { return view('admin.pages.features.form',['item'=>$feature]); } public function update(UpdateFeatureItemRequest $request, FeatureItem $feature, FileUploadService $uploader): RedirectResponse { $data=$this->payload($request->validated()); $data['image']=$uploader->replace($request->file('image'),$feature->image,'uploads/features'); $feature->update($data); $this->clearCache(); return redirect()->route('admin.features.index')->with('success','Feature updated successfully.'); } public function destroy(FeatureItem $feature): RedirectResponse { $feature->delete(); $this->clearCache(); return back()->with('success','Feature deleted successfully.'); } private function payload(array $data): array { $data['status']=(bool)($data['status']??false); $data['sort_order']=(int)($data['sort_order']??0); return $data; } private function clearCache(): void { Cache::forget('feature_items_active_ordered'); } }
